        if (parent is Target t) { Console.WriteLine($"  Target: {t.Name}"); break; }
        if (parent is Microsoft.Build.Logging.StructuredLogger.Task task) { Console.WriteLine($"  Task: {task.Name}"); }
        parent = (parent as TreeNode)?.Parent as BaseNode;
    }
    Console.WriteLine();
}

