using System;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Get top-level project builds (direct children of the build, not nested)
Console.WriteLine("=== PROJECT BUILD ORDER & RESULTS ===");
var allProjects = build.FindChildrenRecursive<Project>();
foreach (var p in allProjects)
{
    var errors = p.FindChildrenRecursive<Error>();
    var errCount = errors.Count();
    var succeeded = errCount == 0;

    // Check if this project has a BuildResult message
    var messages = p.FindChildrenRecursive<Message>();
    var buildResultMsg = messages.FirstOrDefault(m => m.Text != null && m.Text.Contains("Build FAILED"));

    // Check for "project failed" child-project references
    var hasFailedDep = messages.Any(m => m.Text != null && (
        m.Text.Contains("is not up to date") || 
        m.Text.Contains("Build FAILED")));

    if (errCount > 0 || buildResultMsg != null)
    {
        Console.WriteLine($"  {p.Name} (EntryPoint={p.EntryPoint}) errors={errCount}");
        foreach (var e in errors)
            Console.WriteLine($"    [{e.Code}] {e.Text}");
    }
}

// Now look specifically at MSB errors (dependency build failures)
Console.WriteLine();
Console.WriteLine("=== CHECKING FOR MSB4181/CASCADING FAILURES ===");
var msbErrors = build.FindChildrenRecursive<Error>().Where(e => e.Code != null && e.Code.StartsWith("MSB"));
foreach (var e in msbErrors)
    Console.WriteLine($"  [{e.Code}] {e.Text} Project={e.ProjectFile}");

// Check for "previously failed to build" messages
Console.WriteLine();
Console.WriteLine("=== CHECKING FOR CASCADING BUILD MESSAGES ===");
var allMessages = build.FindChildrenRecursive<Message>();
foreach (var m in allMessages)
{
    if (m.Text != null && (m.Text.Contains("previously") || m.Text.Contains("failed") || m.Text.Contains("skipping") || m.Text.Contains("not build")))
        Console.WriteLine($"  {m.Text}");
}

// Get source file content embedded in binlog
Console.WriteLine();
Console.WriteLine("=== EMBEDDED SOURCE FILES ===");
var sourceFiles = build.FindChildrenRecursive<SourceFile>();
foreach (var sf in sourceFiles)
{
    Console.WriteLine($"  SourceFile: {sf.Name}");
}

// Check compiler command lines for context
Console.WriteLine();
Console.WriteLine("=== CSC COMMAND LINES (references) ===");
var cscTasks = build.FindChildrenRecursive<Microsoft.Build.Logging.StructuredLogger.Task>()
    .Where(t => t.Name == "Csc");
foreach (var csc in cscTasks)
{
    var cmdLine = csc.FindChildrenRecursive<Property>().FirstOrDefault(p => p.Name == "CommandLineArguments");
    if (cmdLine != null)
    {
        // Extract references
        var refs = cmdLine.Value.Split(' ')
            .Where(a => a.StartsWith("/reference:"))
            .Select(a => a.Replace("/reference:", "").Trim('"'))
            .Select(a => System.IO.Path.GetFileName(a));
        Console.WriteLine($"  Project: {csc.Parent}");
        Console.WriteLine($"    References: {string.Join(", ", refs)}");
    }

    // Show parameters
    var parameters = csc.FindChildrenRecursive<Parameter>();
    foreach (var param in parameters.Where(p => p.Name == "References"))
    {
        var items = param.FindChildrenRecursive<Item>();
        Console.WriteLine($"  CSC References for project under {csc.Parent}:");
        foreach (var item in items)
            Console.WriteLine($"    - {System.IO.Path.GetFileName(item.Name)}");
    }
}
